struct List { head: Option<Box<Node>> }
struct Node { val: i32, next: Option<Box<Node>> }
impl FromIterator<i32> for List {
    fn from_iter<I: IntoIterator<Item = i32>>(iter: I) -> Self {
        let mut list = List { head: None };
        // To keep the order of the iterator, we should reverse it before building 
        // if it's a DoubleEndedIterator, or maintain a tail pointer.
        // Here is a simple reversed insertion for demonstration.
        for val in iter { 
            list.head = Some(Box::new(Node { val, next: list.head.take() })); 
        }
        list
    }
}

